+                        target_used,
+                        BOOL_TO_STR(current_used > target_used));
+  }
+  // Capacity may have changed during the marking phase. Update the ihop target.
+  if (g1h->capacity() != _target_occupancy) {
+    update_target_occupancy(g1h->capacity());
+  }
+}
